51	fn commas(n: u64) -> String {
52	    let digits = n.to_string();
53	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
54	    for (i, c) in digits.chars().enumerate() {
55	        if i > 0 && (digits.len() - i).is_multiple_of(3) {
56	            out.push(',');
57	        }
58	        out.push(c);
