    let start = Instant::now();
    std::thread::scope(|s| {
        s.spawn(move || {
            for i in 0..COUNT {
                loop {
                    match pool.alloc::<Msg>() {
                        Ok(mut buf) => {
                            buf.seq = i;
                            tx.send(buf).unwrap();
                            break;
                        }
                        Err(Exhausted) => std::hint::spin_loop(),
