/// The composed flow on one thread pinned to cpu 0: alloc a
/// pool message, send its descriptor through the ring,
/// resolve and free it; return elapsed seconds.
fn spsc_ring_one_pool_msg_1t() -> f64 {
    let mut ring_region = Region([0; size_of::<Region>()]);
    let mut pool_region = Region([0; size_of::<Region>()]);
    let mut pool = Pool::init(&mut pool_region.0, CACHE_LINE_SIZE as u32, DEPTH)
        .unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
    let mut registry = PoolRegistry::<1>::new();
    let pool_id = registry
        .register(pool.resolver())
        .unwrap(); // OK: empty capacity-1 registry always has room
    let (mut producer, mut consumer) = Ring::init(&mut ring_region.0, CACHE_LINE_SIZE as u32, DEPTH)
        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
        .split();

    let start = Instant::now();
    std::thread::scope(|s| {
        s.spawn(move || {
            pin_to_cpu(0);
            for i in 0..COUNT {
                let mut buf = pool
                    .alloc::<Msg>()
                    .unwrap(); // OK: alloc+free per iteration, DEPTH never exceeded
                buf.seq = i;
                let desc = registry
                    .into_desc(pool_id, buf)
                    .map_err(|(_, e)| e)
                    .unwrap(); // OK: pool_id came from this registry's register
                match producer.reserve_slot::<Desc>() {
                    Ok(mut slot) => {
                        *slot = desc;
                        slot.commit();
                    }
                    Err(Full) => {
                        panic!("spsc_ring_one_pool_msg_1t: producer Full SHOULD NOT HAPPEN");
                    }
                }
                match consumer.reserve_slot::<Desc>() {
                    Ok(slot) => {
                        let desc = *slot;
                        slot.release();
                        // SAFETY: the desc was consumed into
                        // the ring by into_desc above and is
                        // resolved exactly once, same thread.
                        let msg = unsafe { registry.resolve::<Msg>(desc) }
                            .unwrap(); // OK: desc came from into_desc on this pool
                        assert_eq!(msg.seq, i);
                        msg.free();
                    }
                    Err(Empty) => {
                        panic!("spsc_ring_one_pool_msg_1t: consumer Empty SHOULD NOT HAPPEN");
                    }
                }
            }
        });
    });
    start.elapsed().as_secs_f64()
}

/// The composed flow producer-thread → consumer-thread:
/// alloc + fill pool messages on the producer, descriptors
/// cross the SPSC ring, the consumer resolves and frees;
/// return elapsed seconds.
///
/// - `pin` — `Some((p, c))` pins the producer to cpu `p` and
///   the consumer to cpu `c`; `None` lets the scheduler place
///   them (the number then depends on where they land).
fn spsc_ring_one_pool_msg_2t(pin: PinPair) -> f64 {
    let mut ring_region = Region([0; size_of::<Region>()]);
    let mut pool_region = Region([0; size_of::<Region>()]);
    let mut pool = Pool::init(&mut pool_region.0, CACHE_LINE_SIZE as u32, DEPTH)
        .unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
    let mut registry = PoolRegistry::<1>::new();
    let pool_id = registry
        .register(pool.resolver())
        .unwrap(); // OK: empty capacity-1 registry always has room
    let registry = &registry;
    let (mut producer, mut consumer) = Ring::init(&mut ring_region.0, CACHE_LINE_SIZE as u32, DEPTH)
        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
        .split();

    let start = Instant::now();
    std::thread::scope(|s| {
        s.spawn(move || {
            if let Some((p, _)) = pin {
                pin_to_cpu(p);
            }
            for i in 0..COUNT {
                let mut buf = loop {
                    match pool.alloc::<Msg>() {
                        Ok(buf) => break buf,
                        Err(Exhausted) => std::hint::spin_loop(),
                    }
                };
                buf.seq = i;
                let desc = registry
                    .into_desc(pool_id, buf)
                    .map_err(|(_, e)| e)
                    .unwrap(); // OK: pool_id came from this registry's register
                loop {
                    match producer.reserve_slot::<Desc>() {
                        Ok(mut slot) => {
                            *slot = desc;
                            slot.commit();
                            break;
                        }
                        Err(Full) => std::hint::spin_loop(),
                    }
                }
            }
        });
        s.spawn(move || {
            if let Some((_, c)) = pin {
                pin_to_cpu(c);
            }
            for i in 0..COUNT {
                let desc = loop {
                    match consumer.reserve_slot::<Desc>() {
                        Ok(slot) => {
                            let desc = *slot;
                            slot.release();
                            break desc;
                        }
                        Err(Empty) => std::hint::spin_loop(),
                    }
                };
                // SAFETY: the desc was consumed into the ring
                // by the producer and read after the commit →
                // reserve handoff (happens-before); each is
                // resolved exactly once.
                let msg = unsafe { registry.resolve::<Msg>(desc) }
                    .unwrap(); // OK: descs here only come from the producer's into_desc
                assert_eq!(msg.seq, i);
                msg.free();
            }
        });
    });
    start.elapsed().as_secs_f64()
}

