1	//! Demo binary: both primitives working across threads,
2	//! with throughput printed — run `cargo run --release`, or
3	//! `cargo install --path . --locked` and run
4	//! `zc-ring-x1-demo`. `-V`/`--version` prints the
5	//! version-of-record so you know exactly which build you
6	//! are testing.
7	//!
8	//! - Part 1, the ring: an SPSC pair moves typed messages
9	//!   in place (reserve_slot → write → commit; reserve_slot
10	//!   → read → release) — first both ends on one thread
11	//!   (the ring's own cost), then one producer thread to
12	//!   one consumer thread: unpinned, pinned to one physical
13	//!   core's two SMT siblings (shared L1/L2), and pinned to
14	//!   two different physical cores.
15	//! - Part 2, the pool: an allocator thread allocs and
16	//!   fills `BufSlot`s and hands them to a freer thread —
17	//!   "send" today is moving the guard (see the README's
18	//!   usage model); getting a buffer implies nothing about
19	//!   when it is sent or freed.
20	//! - The composed form — descriptors through the ring,
21	//!   payloads at rest in pool buffers — runs between them:
22	//!   alloc → into_desc → ring → resolve → free, with the
23	//!   same placement ladder as the raw ring.
24	
25	use std::time::Instant;
26	
27	use zc_ring_x1::{
28	    BufSlot, CACHE_LINE_SIZE, Desc, Empty, Exhausted, Full, Pool, PoolRegistry, Ring,
29	};
30	use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
31	
32	/// Messages moved per part.
33	const COUNT: u64 = 1_000_000;
34	
35	/// Ring slots / pool buffers (small on purpose: recycling
36	/// under pressure is the interesting case).
37	const DEPTH: u32 = 64;
38	
39	/// The demo message; one word carrying the sequence number
40	/// the consumer asserts.
41	#[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
42	#[repr(C)]
43	struct Msg {
44	    seq: u64,
45	}
46	
47	/// Region for either primitive: biggest header (ring, 4
48	/// lines) + DEPTH one-line slots/buffers.
49	#[repr(C, align(64))]
50	struct Region([u8; 4 * CACHE_LINE_SIZE + DEPTH as usize * CACHE_LINE_SIZE]);
51	
52	/// Group a count into comma-separated thousands
53	/// (`1234567` → `"1,234,567"`).
54	fn commas(n: u64) -> String {
55	    let digits = n.to_string();
56	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
57	    for (i, c) in digits.chars().enumerate() {
58	        if i > 0 && (digits.len() - i).is_multiple_of(3) {
59	            out.push(',');
60	        }
61	        out.push(c);
62	    }
63	    out
64	}
65	
66	/// Print one part's line: msgs/sec (comma-grouped) and
67	/// ns/msg from the part's elapsed seconds.
68	fn report(label: &str, secs: f64) {
69	    let rate = commas((COUNT as f64 / secs) as u64);
70	    let ns_per_msg = secs * 1e9 / COUNT as f64;
71	    println!("{label:<43} {rate:>12} msgs/sec  {ns_per_msg:>7.1} ns/msg");
72	}
73	
74	/// Parse a /sys cpu-list string ("0,12" or "0-2,6") into cpu
75	/// numbers; malformed pieces are skipped.
76	#[cfg(target_os = "linux")]
77	fn parse_cpu_list(s: &str) -> Vec<usize> {
78	    let mut out = Vec::new();
79	    for part in s.trim().split(',') {
80	        match part.split_once('-') {
81	            Some((lo, hi)) => {
82	                if let (Ok(lo), Ok(hi)) = (lo.parse::<usize>(), hi.parse::<usize>()) {
83	                    out.extend(lo..=hi);
84	                }
85	            }
86	            None => {
87	                if let Ok(n) = part.parse() {
88	                    out.push(n);
89	                }
90	            }
91	        }
92	    }
93	    out
94	}
