input.new_string:
/// The std-channel flow on one thread pinned to cpu 0: alloc
/// a pool message, move its guard through a sync_channel,
/// receive and free it; return elapsed seconds.
fn std_mpsc_one_pool_msg_1t() -> f64 {
    let mut region = Region([0; size_of::<Region>()]);
    let mut pool = Pool::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
        .unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
    let (tx, rx) = std::sync::mpsc::sync_channel::<BufSlot<'_, Msg>>(DEPTH as usize);

    let start = Instant::now();
    std::thread::scope(|s| {
        s.spawn(move || {
            pin_to_cpu(0);
            for i in 0..COUNT {
                let mut buf = pool
                    .alloc::<Msg>()
                    .unwrap(); // OK: alloc+free per iteration, DEPTH never exceeded
                buf.seq = i;
                tx.send(buf).unwrap(); // OK: capacity DEPTH, at most one in flight
                let buf = rx.recv().unwrap(); // OK: just sent on this thread
                assert_eq!(buf.seq, i);
                buf.free();
            }
        });
    });
    start.elapsed().as_secs_f64()
}

