1	//! Demo binary: both primitives working across threads,
2	//! with throughput printed — run `cargo run --release`, or
3	//! `cargo install --path . --locked` and run
4	//! `zc-ring-x1-demo`. `-V`/`--version` prints the
5	//! version-of-record so you know exactly which build you
6	//! are testing.
7	//!
8	//! - Part 1, the ring: an SPSC pair moves typed messages
9	//!   in place (reserve_slot → write → commit; reserve_slot
10	//!   → read → release) — first both ends on one thread
11	//!   (the ring's own cost), then one producer thread to
12	//!   one consumer thread: unpinned, pinned to one physical
13	//!   core's two SMT siblings (shared L1/L2), and pinned to
14	//!   two different physical cores.
15	//! - Part 2, the pool: an allocator thread allocs and
16	//!   fills `BufSlot`s and hands them to a freer thread —
17	//!   "send" today is moving the guard (see the README's
18	//!   usage model); getting a buffer implies nothing about
19	//!   when it is sent or freed.
20	//! - The composed form — descriptors through the ring,
21	//!   payloads at rest in pool buffers — runs between them:
22	//!   alloc → into_desc → ring → resolve → free, with the
23	//!   same placement ladder as the raw ring.
24	
25	use std::time::Instant;
26	
27	use zc_ring_x1::{
28	    BufSlot, CACHE_LINE_SIZE, Desc, Empty, Exhausted, Full, Pool, PoolRegistry, Ring,
29	};
30	use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
31	
32	/// Messages moved per part.
33	const COUNT: u64 = 1_000_000;
34	
35	/// Ring slots / pool buffers (small on purpose: recycling
36	/// under pressure is the interesting case).
37	const DEPTH: u32 = 64;
38	
39	/// The demo message; one word carrying the sequence number
40	/// the consumer asserts.
41	#[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
42	#[repr(C)]
43	struct Msg {
44	    seq: u64,
45	}
46	
47	/// Region for either primitive: biggest header (ring, 4
48	/// lines) + DEPTH one-line slots/buffers.
49	#[repr(C, align(64))]
50	struct Region([u8; 4 * CACHE_LINE_SIZE + DEPTH as usize * CACHE_LINE_SIZE]);
51	
52	/// Group a count into comma-separated thousands
53	/// (`1234567` → `"1,234,567"`).
54	fn commas(n: u64) -> String {
55	    let digits = n.to_string();
56	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
57	    for (i, c) in digits.chars().enumerate() {
58	        if i > 0 && (digits.len() - i).is_multiple_of(3) {
59	            out.push(',');
60	        }
61	        out.push(c);
62	    }
63	    out
64	}
65	
66	/// Print one part's line: msgs/sec (comma-grouped) and
67	/// ns/msg from the part's elapsed seconds.
68	fn report(label: &str, secs: f64) {
69	    let rate = commas((COUNT as f64 / secs) as u64);
70	    let ns_per_msg = secs * 1e9 / COUNT as f64;
71	    println!("{label:<43} {rate:>12} msgs/sec  {ns_per_msg:>7.1} ns/msg");
72	}
73	
74	/// Parse a /sys cpu-list string ("0,12" or "0-2,6") into cpu
75	/// numbers; malformed pieces are skipped.
76	#[cfg(target_os = "linux")]
77	fn parse_cpu_list(s: &str) -> Vec<usize> {
78	    let mut out = Vec::new();
79	    for part in s.trim().split(',') {
80	        match part.split_once('-') {
81	            Some((lo, hi)) => {
82	                if let (Ok(lo), Ok(hi)) = (lo.parse::<usize>(), hi.parse::<usize>()) {
83	                    out.extend(lo..=hi);
84	                }
85	            }
86	            None => {
87	                if let Ok(n) = part.parse() {
88	                    out.push(n);
89	                }
90	            }
91	        }
92	    }
93	    out
94	}
95	
96	/// A `(producer cpu, consumer cpu)` pin for a 2t run;
97	/// `None` means the pair is unavailable / leave unpinned.
98	type PinPair = Option<(usize, usize)>;
99	
100	/// Discover two cpu pairs for the pinned 2t runs from
101	/// /sys/devices/system/cpu; `None` when the machine lacks the
102	/// shape (or not Linux).
103	///
104	/// - `.0` — same physical core: cpu0 and its SMT sibling
105	///   (shared L1/L2, the cheapest handoff).
106	/// - `.1` — different physical cores: cpu0 and a core outside
107	///   cpu0's L3 group when one exists (the farthest handoff),
108	///   else any non-sibling core.
109	#[cfg(target_os = "linux")]
110	fn discover_pin_pairs() -> (PinPair, PinPair) {
111	    let read = |path: &str| std::fs::read_to_string(path).ok();
112	    let siblings = read("/sys/devices/system/cpu/cpu0/topology/thread_siblings_list")
113	        .map(|s| parse_cpu_list(&s))
114	        .unwrap_or_default();
115	    let smt = (siblings.len() >= 2).then(|| (siblings[0], siblings[1]));
116	    let online = read("/sys/devices/system/cpu/online")
117	        .map(|s| parse_cpu_list(&s))
118	        .unwrap_or_default();
119	    let l3 = read("/sys/devices/system/cpu/cpu0/cache/index3/shared_cpu_list")
120	        .map(|s| parse_cpu_list(&s))
121	        .unwrap_or_else(|| siblings.clone());
122	    let far = online
123	        .iter()
124	        .copied()
125	        .find(|c| !l3.contains(c))
126	        .or_else(|| {
127	            online
128	                .iter()
129	                .copied()
130	                .find(|c| *c != 0 && !siblings.contains(c))
131	        });
132	    (smt, far.map(|c| (0, c)))
133	}
134	
135	/// Non-Linux stub: no pinned runs.
136	#[cfg(not(target_os = "linux"))]
137	fn discover_pin_pairs() -> (PinPair, PinPair) {
138	    (None, None)
139	}
140	
141	/// Pin the calling thread to `cpu` via sched_setaffinity;
142	/// panics on failure (a demo run with a silently ignored pin
143	/// would report a mislabeled number).
144	#[cfg(target_os = "linux")]
145	fn pin_to_cpu(cpu: usize) {
146	    // SAFETY: cpu_set_t is a plain bitmask; CPU_ZERO/CPU_SET
147	    // initialize it fully before sched_setaffinity reads it.
148	    unsafe {
149	        let mut set: libc::cpu_set_t = std::mem::zeroed();
150	        libc::CPU_ZERO(&mut set);
151	        libc::CPU_SET(cpu, &mut set);
152	        let rc = libc::sched_setaffinity(0, size_of::<libc::cpu_set_t>(), &set);
153	        assert_eq!(rc, 0, "sched_setaffinity({cpu}) failed");
154	    }
155	}
156	
157	/// Non-Linux stub: pinning is a no-op, so only the 1t runs
158	/// reach it (discover_pin_pairs returns no pairs); present
159	/// so the demo compiles everywhere.
160	#[cfg(not(target_os = "linux"))]
161	fn pin_to_cpu(_cpu: usize) {}
162	
163	/// Move COUNT messages single thread through the ring,
164	/// pinned to cpu 0 for consistency with the pinned 2t runs;
165	/// return elapsed seconds.
166	///
167	/// The loop runs in a scoped thread rather than pinning the
168	/// main thread: spawned threads inherit the main thread's
169	/// affinity mask, which would squeeze every later part onto
170	/// cpu 0.
171	fn spsc_ring_one_msg_1t() -> f64 {
172	    let mut region = Region([0; size_of::<Region>()]);
173	    let (mut producer, mut consumer) = Ring::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
174	        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
175	        .split();
176	
177	    let start = Instant::now();
178	    std::thread::scope(|s| {
179	        s.spawn(move || {
180	            pin_to_cpu(0);
181	            for i in 0..COUNT {
182	                match producer.reserve_slot::<Msg>() {
183	                    Ok(mut slot) => {
184	                        slot.seq = i;
185	                        slot.commit();
186	                    }
187	                    Err(Full) => {
188	                        panic!("spsc_ring_one_msg_1t: producer Full SHOULD NOT HAPPEN");
189	                    }
190	                }
191	                match consumer.reserve_slot::<Msg>() {
192	                    Ok(msg) => {
193	                        assert_eq!(msg.seq, i);
194	                        msg.release();
195	                    }
196	                    Err(Empty) => {
197	                        panic!("spsc_ring_one_msg_1t: consumer Empty SHOULD NOT HAPPEN");
198	                    }
199	                }
200	            }
201	        });
202	    });
203	    start.elapsed().as_secs_f64()
204	}
205	
206	/// Move COUNT messages producer-thread → consumer-thread
207	/// through the ring; return elapsed seconds.
208	///

